namespace sv_d073750929b04075ba1fa6d34b349780;

// Service contracts
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";

    public PersonalInfo ToRecord() => new(FullName, Email, Phone, Address);
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";

    public WorkEntry ToRecord() => new(Company, Title, StartDate!.Value, IsCurrent ? null : EndDate, Description);
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    public Reference ToRecord() => new(Name, Relationship, Email, Phone);
}

@namespace sv_d073750929b04075ba1fa6d34b349780.Components.JobApplication

<nav class="step-indicator mb-4">
    <ol class="d-flex list-unstyled justify-content-between p-0 m-0">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var stepIndex = i;
            var isCurrent = stepIndex == CurrentStep;
            var isCompleted = CompletedSteps.Contains(stepIndex);
            var isFuture = !isCurrent && !isCompleted;

            <li class="step-item flex-fill text-center @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")">
                @if (isCompleted)
                {
                    <button class="btn btn-link step-btn p-0 text-decoration-none" @onclick="() => OnStepClicked.InvokeAsync(stepIndex)">
                        <span class="step-circle">&#10003;</span>
                        <span class="step-label">@StepNames[stepIndex]</span>
                    </button>
                }
                else
                {
                    <div class="step-btn p-0">
                        <span class="step-circle">@(stepIndex + 1)</span>
                        <span class="step-label">@StepNames[stepIndex]</span>
                    </div>
                }
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

.step-indicator ol {
    counter-reset: step;
}

.step-item {
    position: relative;
}

.step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 18px;
    left: calc(50% + 20px);
    width: calc(100% - 40px);
    height: 2px;
    background-color: #dee2e6;
    z-index: 0;
}

.step-item.completed:not(:last-child)::after {
    background-color: #198754;
}

.step-btn {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.35rem;
    border: none;
    background: none;
    cursor: default;
}

button.step-btn {
    cursor: pointer;
}

.step-circle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 36px;
    height: 36px;
    border-radius: 50%;
    font-weight: 600;
    font-size: 0.9rem;
    z-index: 1;
    background-color: #dee2e6;
    color: #6c757d;
}

.step-item.active .step-circle {
    background-color: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    background-color: #198754;
    color: #fff;
}

.step-label {
    font-size: 0.8rem;
    color: #6c757d;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-item.future .step-label {
    color: #adb5bd;
}

.step-item.future .step-circle {
    background-color: #e9ecef;
    color: #adb5bd;
}

@namespace sv_d073750929b04075ba1fa6d34b349780.Components.JobApplication

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Position @(Index + 1)</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Entry.Company"
                       @onchange="e => { Entry.Company = e.Value?.ToString() ?? string.Empty; OnChanged.InvokeAsync(); }" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Entry.Title"
                       @onchange="e => { Entry.Title = e.Value?.ToString() ?? string.Empty; OnChanged.InvokeAsync(); }" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control" value="@Entry.StartDate?.ToString("yyyy-MM-dd")"
                       @onchange="e => { Entry.StartDate = string.IsNullOrEmpty(e.Value?.ToString()) ? null : DateTime.Parse(e.Value.ToString()!); OnChanged.InvokeAsync(); }" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@Entry.EndDate?.ToString("yyyy-MM-dd")" disabled="@Entry.IsCurrent"
                       @onchange="e => { Entry.EndDate = string.IsNullOrEmpty(e.Value?.ToString()) ? null : DateTime.Parse(e.Value.ToString()!); OnChanged.InvokeAsync(); }" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input type="checkbox" class="form-check-input" id="@($"current-{Index}")" checked="@Entry.IsCurrent"
                           @onchange="e => { Entry.IsCurrent = (bool)(e.Value ?? false); if (Entry.IsCurrent) Entry.EndDate = null; OnChanged.InvokeAsync(); }" />
                    <label class="form-check-label" for="@($"current-{Index}")">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" value="@Entry.Description"
                          @onchange="e => { Entry.Description = e.Value?.ToString() ?? string.Empty; OnChanged.InvokeAsync(); }"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntryModel Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
    [Parameter] public EventCallback OnChanged { get; set; }
}

