@namespace sv_d073750929b04075ba1fa6d34b349780.Components.JobApplication

<div class="card">
    <div class="card-header"><h5 class="mb-0">Personal Information</h5></div>
    <div class="card-body">
        @if (!string.IsNullOrEmpty(ErrorMessage))
        {
            <div class="alert alert-danger">@ErrorMessage</div>
        }

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Full Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Model.FullName" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" @bind="Model.Email" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control" @bind="Model.Phone" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Address <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Model.Address" />
            </div>
        </div>

        <div class="d-flex justify-content-end mt-4">
            <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
                @if (IsValidating)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                    <text>Validating…</text>
                }
                else
                {
                    <text>Next</text>
                }
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private string? ErrorMessage;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            ErrorMessage = "All fields are required.";
            return;
        }

        if (ValidateEmail is not null)
        {
            IsValidating = true;
            StateHasChanged();

            var isValid = await ValidateEmail(Model.Email);
            IsValidating = false;

            if (!isValid)
            {
                ErrorMessage = "The email address is not valid.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_d073750929b04075ba1fa6d34b349780.Components.JobApplication

<div class="card">
    <div class="card-header"><h5 class="mb-0">Work History</h5></div>
    <div class="card-body">
        @if (!string.IsNullOrEmpty(ErrorMessage))
        {
            <div class="alert alert-danger">@ErrorMessage</div>
        }

        @for (int i = 0; i < Entries.Count; i++)
        {
            var index = i;
            <WorkEntryForm Entry="Entries[index]"
                           Index="index"
                           ShowRemove="Entries.Count > 1"
                           OnRemove="() => RemoveEntry(index)"
                           OnChanged="StateHasChanged" />
        }

        <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
            + Add Another Position
        </button>

        <div class="d-flex justify-content-between mt-3">
            <button class="btn btn-secondary" @onclick="OnBack">Back</button>
            <button class="btn btn-primary" @onclick="HandleNext">Next</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) ||
                string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate is null)
            {
                ErrorMessage = "Each position must have a company name, job title, and start date.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_d073750929b04075ba1fa6d34b349780.Components.JobApplication

<div class="card">
    <div class="card-header"><h5 class="mb-0">References</h5></div>
    <div class="card-body">
        @if (!string.IsNullOrEmpty(ErrorMessage))
        {
            <div class="alert alert-danger">@ErrorMessage</div>
        }

        @for (int i = 0; i < References.Count; i++)
        {
            var index = i;
            <ReferenceForm Reference="References[index]"
                           Index="index"
                           ShowRemove="References.Count > 2"
                           OnRemove="() => RemoveReference(index)"
                           OnChanged="StateHasChanged" />
        }

        @if (References.Count < 3)
        {
            <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
                + Add Reference
            </button>
        }

        <div class="d-flex justify-content-between mt-3">
            <button class="btn btn-secondary" @onclick="OnBack">Back</button>
            <button class="btn btn-primary" @onclick="HandleNext">Next</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (References.Count < 2)
        {
            ErrorMessage = "At least 2 references are required.";
            return;
        }

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) ||
                string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) ||
                string.IsNullOrWhiteSpace(r.Phone))
            {
                ErrorMessage = "All fields are required for each reference.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_d073750929b04075ba1fa6d34b349780.Components.JobApplication

<div class="card">
    <div class="card-header"><h5 class="mb-0">Cover Letter</h5></div>
    <div class="card-body">
        @if (!string.IsNullOrEmpty(ErrorMessage))
        {
            <div class="alert alert-danger">@ErrorMessage</div>
        }

        <div class="mb-3">
            <label class="form-label">Write your cover letter</label>
            <textarea class="form-control" rows="12" maxlength="@MaxLength"
                      @bind="CoverLetter" @bind:event="oninput"></textarea>
            <div class="form-text text-end">
                @(CoverLetter?.Length ?? 0) / @MaxLength characters
            </div>
        </div>

        <div class="d-flex justify-content-between mt-3">
            <button class="btn btn-secondary" @onclick="OnBack">Back</button>
            <button class="btn btn-primary" @onclick="HandleNext">Next</button>
        </div>
    </div>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            ErrorMessage = "A cover letter is required.";
            return;
        }

        await CoverLetterChanged.InvokeAsync(CoverLetter);
        await OnNext.InvokeAsync();
    }
}

@namespace sv_d073750929b04075ba1fa6d34b349780.Components.JobApplication

<div class="card">
    <div class="card-header"><h5 class="mb-0">Review &amp; Submit</h5></div>
    <div class="card-body">
        @if (!string.IsNullOrEmpty(ErrorMessage))
        {
            <div class="alert alert-danger">@ErrorMessage</div>
        }

        @if (SubmittedId.HasValue)
        {
            <div class="alert alert-success text-center">
                <h4 class="alert-heading">Application Submitted!</h4>
                <p class="mb-0">Your application ID is <strong>#@SubmittedId</strong>. We'll be in touch!</p>
            </div>
        }
        else
        {
            <!-- Personal Info -->
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="fw-bold">Personal Information</h6>
