    align-items: center;
    justify-content: center;
    width: 36px;
    height: 36px;
    border-radius: 50%;
    font-weight: 600;
    font-size: 0.9rem;
    z-index: 1;
    background-color: #dee2e6;
    color: #6c757d;
}

.step-item.active .step-circle {
    background-color: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    background-color: #198754;
    color: #fff;
}

.step-label {
    font-size: 0.8rem;
