{"path": "/tmp/sv-d073750929b04075ba1fa6d34b349780/Components/JobApplication/ReviewStep.razor", "file_text": "@namespace sv_d073750929b04075ba1fa6d34b349780.Components.JobApplication

<div class="card">
    <div class="card-header"><h5 class="mb-0">Review &amp; Submit</h5></div>
    <div class="card-body">
        @if (!string.IsNullOrEmpty(ErrorMessage))
        {
            <div class="alert alert-danger">@ErrorMessage</div>
        }

        @if (SubmittedId.HasValue)
        {
            <div class="alert alert-success text-center">
                <h4 class="alert-heading">Application Submitted!</h4>
                <p class="mb-0">Your application ID is <strong>#@SubmittedId</strong>. We'll be in touch!</p>
            </div>
        }
        else
        {
            <!-- Personal Info -->
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="fw-bold">Personal Information</h6>
                    <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(0)">Edit</button>
                </div>
                <dl class="row mb-0 ms-1">
                    <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@Personal.FullName</dd>
                    <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@Personal.Email</dd>
                    <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Personal.Phone</dd>
                    <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Personal.Address</dd>
