toolArgs.file_text:
.step-indicator ol {
    counter-reset: step;
}

.step-item {
    position: relative;
}

.step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 18px;
    left: calc(50% + 20px);
    width: calc(100% - 40px);
    height: 2px;
    background-color: #dee2e6;
    z-index: 0;
}

.step-item.completed:not(:last-child)::after {
    background-color: #198754;
}

.step-btn {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.35rem;
    border: none;
    background: none;
    cursor: default;
}

button.step-btn {
    cursor: pointer;
}

.step-circle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 36px;
    height: 36px;
    border-radius: 50%;
    font-weight: 600;
    font-size: 0.9rem;
    z-index: 1;
    background-color: #dee2e6;
    color: #6c757d;
}

.step-item.active .step-circle {
    background-color: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    background-color: #198754;
    color: #fff;
}

.step-label {
    font-size: 0.8rem;
    color: #6c757d;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-item.future .step-label {
    color: #adb5bd;
}

.step-item.future .step-circle {
    background-color: #e9ecef;
    color: #adb5bd;
}

