@namespace sv_d073750929b04075ba1fa6d34b349780.Components.JobApplication

<div class="card">
    <div class="card-header"><h5 class="mb-0">Review &amp; Submit</h5></div>
    <div class="card-body">
        @if (!string.IsNullOrEmpty(ErrorMessage))
        {
            <div class="alert alert-danger">@ErrorMessage</div>
        }

        @if (SubmittedId.HasValue)
        {
            <div class="alert alert-success text-center">
                <h4 class="alert-heading">Application Submitted!</h4>
                <p class="mb-0">Your application ID is <strong>#@SubmittedId</strong>. We'll be in touch!</p>
            </div>
        }
        else
        {
            <!-- Personal Info -->
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="fw-bold">Personal Information</h6>
                    <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(0)">Edit</button>
                </div>
                <dl class="row mb-0 ms-1">
                    <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@Personal.FullName</dd>
                    <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@Personal.Email</dd>
                    <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Personal.Phone</dd>
                    <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Personal.Address</dd>
                </dl>
            </div>
            <hr />

            <!-- Work History -->
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="fw-bold">Work History</h6>
                    <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
                </div>
                @foreach (var entry in WorkEntries)
                {
                    <div class="ms-1 mb-2">
                        <strong>@entry.Title</strong> at @entry.Company<br />
                        <small class="text-muted">
                            @entry.StartDate?.ToString("MMM yyyy") –
                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                        </small>
                        @if (!string.IsNullOrWhiteSpace(entry.Description))
                        {
                            <p class="mb-0 mt-1">@entry.Description</p>
                        }
                    </div>
                }
            </div>
            <hr />

            <!-- References -->
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="fw-bold">References</h6>
                    <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
                </div>
                @foreach (var r in References)
                {
                    <div class="ms-1 mb-2">
                        <strong>@r.Name</strong> — @r.Relationship<br />
                        <small class="text-muted">@r.Email · @r.Phone</small>
                    </div>
                }
            </div>
            <hr />

            <!-- Cover Letter -->
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="fw-bold">Cover Letter</h6>
                    <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
                </div>
                <div class="ms-1" style="white-space: pre-wrap;">@CoverLetter</div>
            </div>

            <div class="d-flex justify-content-between mt-4">
                <button class="btn btn-secondary" @onclick="OnBack">Back</button>
                <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
                    @if (IsSubmitting)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                        <text>Submitting…</text>
                    }
                    else
                    {
                        <text>Submit Application</text>
                    }
                </button>
            </div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEditSection { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    public int? SubmittedId { get; set; }
    private string? ErrorMessage;
    private bool IsSubmitting;

    [Parameter] public Func<Task<int>>? SubmitApplication { get; set; }

    private async Task HandleSubmit()
    {
        ErrorMessage = null;
        IsSubmitting = true;

        try
        {
            if (SubmitApplication is not null)
            {
                SubmittedId = await SubmitApplication();
            }
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

